Use ASP.NET Core's **`WebApplicationFactory<T>`** — it hosts your app in-memory and gives you an `HttpClient` that routes requests through the middleware pipeline with no real network socket.

Here's the pattern:

```csharp
// 1. Add these test project dependencies:
//    Microsoft.AspNetCore.Mvc.Testing
//    xunit / NUnit / MSTest

// 2. Create a fixture using your Program entry point:
public class McpTests : IClassFixture<WebApplicationFactory<Program>>
{
    private readonly HttpClient _client;

    public McpTests(WebApplicationFactory<Program> factory)
    {
        _client = factory.CreateClient();
    }

    [Fact]
    public async Task Initialize_ReturnsServerCapabilities()
    {
        // Send a JSON-RPC "initialize" request per the MCP spec
        var request = new
        {
            jsonrpc = "2.0",
            id = 1,
            method = "initialize",
            @params = new
            {
                protocolVersion = "2025-03-26",
                capabilities = new { },
                clientInfo = new { name = "test-client", version = "1.0" }
            }
        };

        var response = await _client.PostAsJsonAsync("/mcp", request);

        response.EnsureSuccessStatusCode();
        var body = await response.Content.ReadFromJsonAsync<JsonElement>();
        Assert.Equal("2.0", body.GetProperty("jsonrpc").GetString());
        Assert.Equal(1, body.GetProperty("id").GetInt32());
        Assert.True(body.GetProperty("result").TryGetProperty("capabilities", out _));
    }

    [Fact]
    public async Task ToolsList_ReturnsRegisteredTools()
    {
        var request = new { jsonrpc = "2.0", id = 2, method = "tools/list" };

        var response = await _client.PostAsJsonAsync("/mcp", request);

        response.EnsureSuccessStatusCode();
        var body = await response.Content.ReadFromJsonAsync<JsonElement>();
        var tools = body.GetProperty("result").GetProperty("tools");
        Assert.True(tools.GetArrayLength() > 0);
    }
}
```

**Key points:**

- **No real port** — `WebApplicationFactory` creates an in-process `TestServer`; the `HttpClient` talks to it directly via an in-memory transport.
- **Full pipeline** — middleware, routing, DI, and serialization all run exactly as in production.
- **Mock dependencies** — override services in the DI container via `factory.WithWebHostBuilder(b => b.ConfigureServices(...))` to stub databases, external APIs, etc.
- **SSE / Streamable HTTP** — if your MCP endpoint uses SSE, read the response stream incrementally with `HttpCompletionOption.ResponseHeadersRead` and `ReadAsStreamAsync()`.
- Make sure `Program` is accessible to your test project (add `InternalsVisibleTo` or a `public partial class Program { }` stub).
